const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// --- API Keys (for development environment as requested) ---
const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token_here'; // Replace with your actual Twilio Auth Token
const TWILIO_PHONE_NUMBER = '+15017122661'; // Replace with your actual Twilio Phone Number (e.g., +1XXXXXXXXXX)

sgMail.setApiKey(SENDGRID_API_KEY);
const twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

module.exports = async function (context, req) {
    context.log('HTTP trigger function processed a request.');

    if (!req.body) {
        context.res = {
            status: 400,
            body: "Please pass an email or sms object in the request body."
        };
        return;
    }

    const { email, sms } = req.body;
    const results = {};
    let hasErrors = false;

    // --- Send Email via SendGrid ---
    if (email) {
        context.log('Attempting to send email...');
        const msg = {
            to: email.to,
            from: email.from || 'test@example.com', // Default 'from' if not provided
            subject: email.subject || 'Hello from Azure Function',
            text: email.text || 'This is a test email from your Azure Function!',
            html: email.html || '<strong>This is a test email from your Azure Function!</strong>',
        };

        try {
            await sgMail.send(msg);
            results.email = { status: 'success', message: 'Email sent successfully.' };
            context.log('Email sent successfully.');
        } catch (error) {
            context.error('Error sending email:', error);
            results.email = { status: 'error', message: error.message || 'Failed to send email.' };
            hasErrors = true;
        }
    }

    // --- Send SMS via Twilio ---
    if (sms) {
        context.log('Attempting to send SMS...');
        if (!sms.to || !sms.body) {
            results.sms = { status: 'error', message: 'SMS recipient and body are required.' };
            hasErrors = true;
        } else {
            try {
                const message = await twilioClient.messages.create({
                    body: sms.body,
                    from: TWILIO_PHONE_NUMBER,
                    to: sms.to,
                });
                results.sms = { status: 'success', message: `SMS sent successfully. SID: ${message.sid}` };
                context.log(`SMS sent successfully. SID: ${message.sid}`);
            } catch (error) {
                context.error('Error sending SMS:', error);
                results.sms = { status: 'error', message: error.message || 'Failed to send SMS.' };
                hasErrors = true;
            }
        }
    }

    if (!email && !sms) {
        context.res = {
            status: 400,
            body: "Request body must contain 'email' or 'sms' object."
        };
        return;
    }

    context.res = {
        status: hasErrors ? 500 : 200,
        body: results
    };
};